import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import './ERPChatBot.css';
import {
  Send, Bot, User, HelpCircle, X, Maximize2, Minimize2,
  Calendar, DollarSign, BarChart3, Clock, BookOpen,
  Award, FileText, Users, Menu, Search
} from 'lucide-react';

const ChatbotInterface = () => {
  const [messages, setMessages] = useState([
    {
      id: 1,
      text: "Hello! I'm your ERP assistant. How can I help you today? 👋",
      sender: 'bot',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [quickActions, setQuickActions] = useState([]);
  const [suggestions, setSuggestions] = useState([]);
  const messagesEndRef = useRef(null);
  const chatContainerRef = useRef(null);

 

  useEffect(() => {
    setQuickActions(defaultQuickActions);
    setSuggestions(exampleQueries);
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const sendMessage = async (text = inputText) => {
    if (!text.trim() || isLoading) return;

    const userMessage = {
      id: messages.length + 1,
      text: text,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      // Get studentId from session/localStorage
      const studentId = localStorage.getItem('studentId') || 
                       sessionStorage.getItem('studentId') ||
                       'demo123'; // Fallback for demo

      const response = await axios.post('/api/chatbot/chat', {
        query: text,
        studentId: studentId
      }, {
        headers: {
          'Content-Type': 'application/json'
        }
      });

      if (response.data.success) {
        const botMessage = {
          id: messages.length + 2,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          data: response.data.data,
          intent: response.data.intent,
          studentName: response.data.studentName
        };
        setMessages(prev => [...prev, botMessage]);
      } else {
        throw new Error(response.data.message);
      }
    } catch (error) {
      console.error('Chatbot error:', error);
      const errorMessage = {
        id: messages.length + 2,
        text: error.response?.data?.message || "Sorry, I'm having trouble connecting. Please try again.",
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickAction = (query) => {
    sendMessage(query);
  };

  const handleSuggestionClick = (suggestion) => {
    setInputText(suggestion);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = () => {
    setMessages([
      {
        id: 1,
        text: "Hello! I'm your ERP assistant. How can I help you today? 👋",
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }
    ]);
  };

  const formatMessage = (text) => {
    // Format markdown-like text
    const parts = text.split(/(\*\*.*?\*\*|✅|⚠️|❌|💰|📊|📅|📈|📚|👤|🎉|🏠|📝)/g);
    
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={index} className="message-bold">{part.slice(2, -2)}</strong>;
      }
      
      // Add icons
      const iconMap = {
        '✅': '✅',
        '⚠️': '⚠️',
        '❌': '❌',
        '💰': '💰',
        '📊': '📊',
        '📅': '📅',
        '📈': '📈',
        '📚': '📚',
        '👤': '👤',
        '🎉': '🎉',
        '🏠': '🏠',
        '📝': '📝',
      };
      
      if (iconMap[part]) {
        return <span key={index} className="message-icon">{part}</span>;
      }
      
      // Handle line breaks
      if (part.includes('\n')) {
        return part.split('\n').map((line, i) => (
          <React.Fragment key={`${index}-${i}`}>
            {line}
            {i < part.split('\n').length - 1 && <br />}
          </React.Fragment>
        ));
      }
      
      return part;
    });
  };

  return (
    <>
      {/* Chatbot Button */}
      {!isOpen && (
        <button 
          className="chatbot-toggle-btn"
          onClick={() => setIsOpen(true)}
        >
          <Bot size={24} />
          <span className="chatbot-pulse"></span>
        </button>
      )}

      {/* Chatbot Modal */}
      {isOpen && (
        <div className={`chatbot-modal ${isMinimized ? 'minimized' : ''}`}>
          {/* Header */}
          <div className="chatbot-header">
            <div className="chatbot-title">
              <Bot size={20} />
              <div>
                <h3>ERP Assistant</h3>
                <p className="chatbot-subtitle">AI-powered student support</p>
              </div>
            </div>
            <div className="chatbot-actions">
              <button 
                className="icon-btn"
                onClick={() => setIsMinimized(!isMinimized)}
                title={isMinimized ? "Maximize" : "Minimize"}
              >
                {isMinimized ? <Maximize2 size={18} /> : <Minimize2 size={18} />}
              </button>
              <button 
                className="icon-btn"
                onClick={clearChat}
                title="Clear chat"
              >
                <Menu size={18} />
              </button>
              <button 
                className="icon-btn close-btn"
                onClick={() => setIsOpen(false)}
                title="Close"
              >
                <X size={18} />
              </button>
            </div>
          </div>

          {!isMinimized && (
            <>
              {/* Messages Container */}
              <div className="chatbot-messages" ref={chatContainerRef}>
                {messages.map((msg) => (
                  <div 
                    key={msg.id} 
                    className={`message ${msg.sender}`}
                  >
                    <div className="message-avatar">
                      {msg.sender === 'bot' ? (
                        <div className="avatar-bot">
                          <Bot size={16} />
                        </div>
                      ) : (
                        <div className="avatar-user">
                          <User size={16} />
                        </div>
                      )}
                    </div>
                    <div className="message-content">
                      <div className="message-text">
                        {formatMessage(msg.text)}
                      </div>
                      <div className="message-timestamp">
                        {msg.timestamp}
                      </div>
                      {msg.data && msg.intent && (
                        <div className="message-meta">
                          <span className="intent-badge">{msg.intent}</span>
                          {msg.studentName && (
                            <span className="student-badge">{msg.studentName}</span>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
                
                {isLoading && (
                  <div className="message bot">
                    <div className="message-avatar">
                      <div className="avatar-bot">
                        <Bot size={16} />
                      </div>
                    </div>
                    <div className="message-content">
                      <div className="typing-indicator">
                        <span></span>
                        <span></span>
                        <span></span>
                      </div>
                    </div>
                  </div>
                )}
                
                <div ref={messagesEndRef} />
              </div>

              {/* Quick Actions */}
              <div className="quick-actions">
                <div className="quick-actions-header">
                  <HelpCircle size={16} />
                  <span>Quick Actions</span>
                </div>
                <div className="quick-actions-grid">
                  {quickActions.map((action, index) => (
                    <button
                      key={index}
                      className="quick-action-btn"
                      onClick={() => handleQuickAction(action.query)}
                      title={action.query}
                    >
                      {action.icon}
                      <span>{action.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Suggestions */}
              {suggestions.length > 0 && (
                <div className="suggestions">
                  <div className="suggestions-header">
                    <Search size={16} />
                    <span>Try asking:</span>
                  </div>
                  <div className="suggestions-list">
                    {suggestions.map((suggestion, index) => (
                      <button
                        key={index}
                        className="suggestion-chip"
                        onClick={() => handleSuggestionClick(suggestion)}
                      >
                        {suggestion}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Input Area */}
              <div className="chatbot-input">
                <div className="input-wrapper">
                  <input
                    type="text"
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Ask about fees, attendance, timetable, results..."
                    disabled={isLoading}
                  />
                  <button 
                    className="send-btn"
                    onClick={() => sendMessage()}
                    disabled={!inputText.trim() || isLoading}
                  >
                    {isLoading ? (
                      <div className="loading-spinner"></div>
                    ) : (
                      <Send size={20} />
                    )}
                  </button>
                </div>
                <div className="input-hint">
                  Press Enter to send • Shift+Enter for new line
                </div>
              </div>
            </>
          )}
        </div>
      )}
    </>
  );
};

export default ChatbotInterface;
